import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Cookie from 'cookie-universal';
import Axios, { COURSES, ADMIN_COURSES, INSTRUCTORS } from '../../Api/Api';
import '../../styles/Dashboard.css';

export default function Dashboard() {
  const navigate = useNavigate();
  const cookie = Cookie();

  const [courses, setCourses] = useState([]);
  const [instructors, setInstructors] = useState([]);  // ← جديد
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [currentCourse, setCurrentCourse] = useState(null);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    price: '',
    rating: '',
    image: '',
    instructor_id: '',  // ← تعديل
    is_featured: false
  });
  const [formLoading, setFormLoading] = useState(false);

  function getCurrentUser() {
    const user = cookie.get('educational-user');
    if (!user) return null;
    return typeof user === 'string' ? JSON.parse(user) : user;
  }

  useEffect(() => {
    const userData = getCurrentUser();
    
    if (!userData) {
      navigate('/login');
      return;
    }

    if (userData.role !== 'admin') {
      alert('غير مصرح لك بالوصول لهذه الصفحة');
      navigate('/');
      return;
    }

    loadCourses();
    loadInstructors();  // ← جديد
  }, []);

  function loadCourses() {
    setLoading(true);
    Axios.get(`/${COURSES}`)
      .then(res => {
        setCourses(res.data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }

  // ← جديد - جلب المدرسين
  function loadInstructors() {
    Axios.get(`/${INSTRUCTORS}`)
      .then(res => {
        setInstructors(res.data);
      })
      .catch(err => {
        console.error(err);
      });
  }

  function openAddModal() {
    setEditMode(false);
    setCurrentCourse(null);
    setFormData({
      title: '',
      description: '',
      price: '',
      rating: '',
      image: '',
      instructor_id: '',  // ← تعديل
      is_featured: false
    });
    setShowModal(true);
  }

  function openEditModal(course) {
    setEditMode(true);
    setCurrentCourse(course);
    setFormData({
      title: course.title,
      description: course.description,
      price: course.price,
      rating: course.rating,
      image: course.image,
      instructor_id: course.instructor?.id || '',  // ← تعديل
      is_featured: course.is_featured || false
    });
    setShowModal(true);
  }

  function handleChange(e) {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === 'checkbox' ? checked : value
    });
  }

  async function handleSubmit(e) {
    e.preventDefault();
    setFormLoading(true);

    try {
      if (editMode) {
        await Axios.put(`/${ADMIN_COURSES}/${currentCourse.id}`, formData);
        alert('تم تعديل الكورس بنجاح ✅');
      } else {
        await Axios.post(`/${ADMIN_COURSES}`, formData);
        alert('تم إضافة الكورس بنجاح ✅');
      }

      setShowModal(false);
      loadCourses();
      setFormLoading(false);
    } catch (error) {
      console.error(error);
      alert('حدث خطأ: ' + (error.response?.data?.message || 'حاول مرة أخرى'));
      setFormLoading(false);
    }
  }

  async function handleDelete(id, title) {
    if (!window.confirm(`هل أنت متأكد من حذف الكورس "${title}"؟`)) {
      return;
    }

    try {
      await Axios.delete(`/${ADMIN_COURSES}/${id}`);
      alert('تم حذف الكورس بنجاح ✅');
      loadCourses();
    } catch (error) {
      console.error(error);
      alert('حدث خطأ في الحذف');
    }
  }

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>جاري التحميل...</p>
      </div>
    );
  }

  return (
    <div className="dashboard-page">
      <div className="dashboard-header">
        <div className="container">
          <h1>لوحة تحكم الأدمن 👑</h1>
          <button onClick={openAddModal} className="add-btn">
            ➕ إضافة كورس جديد
          </button>
        </div>
      </div>

      <div className="dashboard-content">
        <div className="container">
          <div className="stats-cards">
            <div className="stat-card">
              <h3>إجمالي الكورسات</h3>
              <p className="stat-number">{courses.length}</p>
            </div>
            <div className="stat-card">
              <h3>الكورسات المميزة</h3>
              <p className="stat-number">
                {courses.filter(c => c.is_featured).length}
              </p>
            </div>
            <div className="stat-card">
              <h3>متوسط السعر</h3>
              <p className="stat-number">
                ${(courses.reduce((sum, c) => sum + parseFloat(c.price), 0) / courses.length).toFixed(2)}
              </p>
            </div>
          </div>

          <div className="table-container">
            <table className="courses-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>العنوان</th>
                  <th>المدرب</th>
                  <th>السعر</th>
                  <th>التقييم</th>
                  <th>مميز</th>
                  <th>الإجراءات</th>
                </tr>
              </thead>
              <tbody>
                {courses.map(course => (
                  <tr key={course.id}>
                    <td>{course.id}</td>
                    <td className="course-title-cell">{course.title}</td>
                    <td>{course.instructor ? course.instructor.name : '-'}</td>
                    <td className="price-cell">${course.price}</td>
                    <td>⭐ {course.rating}</td>
                    <td>
                      {course.is_featured ? (
                        <span className="badge featured">نعم</span>
                      ) : (
                        <span className="badge">لا</span>
                      )}
                    </td>
                    <td>
                      <div className="action-buttons">
                        <button 
                          onClick={() => openEditModal(course)}
                          className="edit-btn"
                          title="تعديل"
                        >
                          ✏️
                        </button>
                        <button 
                          onClick={() => handleDelete(course.id, course.title)}
                          className="delete-btn"
                          title="حذف"
                        >
                          🗑️
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{editMode ? '✏️ تعديل الكورس' : '➕ إضافة كورس جديد'}</h2>
              <button onClick={() => setShowModal(false)} className="close-btn">
                ✖
              </button>
            </div>

            <form onSubmit={handleSubmit} className="course-form">
              <div className="form-row">
                <div className="form-group">
                  <label>عنوان الكورس *</label>
                  <input
                    type="text"
                    name="title"
                    value={formData.title}
                    onChange={handleChange}
                    required
                    placeholder="مثال: تطوير تطبيقات الويب"
                  />
                </div>

                <div className="form-group">
                  <label>المدرب *</label>
                  <select
                    name="instructor_id"
                    value={formData.instructor_id}
                    onChange={handleChange}
                    required
                  >
                    <option value="">اختر المدرب</option>
                    {instructors.map(instructor => (
                      <option key={instructor.id} value={instructor.id}>
                        {instructor.name} - {instructor.specialization}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="form-group">
                <label>الوصف *</label>
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleChange}
                  required
                  rows="4"
                  placeholder="وصف تفصيلي عن الكورس..."
                />
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>السعر ($) *</label>
                  <input
                    type="number"
                    name="price"
                    value={formData.price}
                    onChange={handleChange}
                    required
                    min="0"
                    step="0.01"
                    placeholder="99.99"
                  />
                </div>

                <div className="form-group">
                  <label>التقييم (0-5) *</label>
                  <input
                    type="number"
                    name="rating"
                    value={formData.rating}
                    onChange={handleChange}
                    required
                    min="0"
                    max="5"
                    step="0.1"
                    placeholder="4.5"
                  />
                </div>
              </div>

              <div className="form-group">
                <label>رابط الصورة *</label>
                <input
                  type="text"
                  name="image"
                  value={formData.image}
                  onChange={handleChange}
                  required
                  placeholder="https://example.com/image.jpg"
                />
              </div>

              <div className="form-group checkbox-group">
                <label>
                  <input
                    type="checkbox"
                    name="is_featured"
                    checked={formData.is_featured}
                    onChange={handleChange}
                  />
                  <span>كورس مميز (يظهر في الصفحة الرئيسية)</span>
                </label>
              </div>

              <div className="modal-footer">
                <button type="button" onClick={() => setShowModal(false)} className="cancel-btn">
                  إلغاء
                </button>
                <button type="submit" className="submit-btn" disabled={formLoading}>
                  {formLoading ? 'جاري الحفظ...' : (editMode ? 'حفظ التعديلات' : 'إضافة الكورس')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
